import type { TruncationMode } from '../../../typography/text-ellipsis/TextEllipsis.js';
import type { BaseAnnotationsChartProps } from '../../core/components/annotations/types/annotations.js';
import type { TextOverflowOptions } from '../../core/components/annotations/types/marker.js';
/**
 * The AnnotationsChart component props
 * @public
 */
export interface AnnotationsChartProps extends BaseAnnotationsChartProps {
    /**
     * Custom width of the tracks labels.
     * @defaultValue 60
     */
    labelWidth?: number;
    /**
     * Show the loading indicator when truly.
     * @defaultValue false
     */
    loading?: boolean;
    /**
     * The height of the chart. If a number is passed, it will be treated as px.
     * @defaultValue 300px
     */
    height?: number | string;
    /**
     * The width of the chart. If a number is passed, it will be treated as px.
     * @defaultValue "100%"
     */
    width?: number | string;
    /** Truncate will keep markers width */
    textOverflow?: TextOverflowOptions;
    /** Where to truncate the text */
    truncateMode?: TruncationMode;
    /**
     * Maximum number of lines used to clamp the default tooltip content
     * (header text, series name, and series description). Values greater than
     * `1` enable multi-line wrapping before truncation is applied. Combine with
     * `truncateMode` to control where the overflow ellipsis appears.
     * @defaultValue 1
     */
    maxLines?: number;
}
